<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t(projectTeamName) }} </h4>
                        <button type="button" class="close" v-on:click="CloseAddBacklog">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <div class="row">                
                            <div class="col-md-12 pt-2 listing">
                                <div class="table-responsive table-fix-header float-left" style="max-height:530px;">
                                    <table id="mainTable" class="table table-bordered dt-responsive nowrap mt-0">
                                        <thead class="thead-bg">
                                            <tr>                                                
                                                <th style="min-width:150px;"><span>{{ $t(projectTeamName) }} {{ $t('Name') }}</span></th>
                                                <th style="min-width:150px;"><span>{{ $t('AliasName') }}</span></th>
                                                <th style="min-width:150px;" class="text-center"><span>{{ $t(projectTeamName) }} {{ $t('USER_ROLE') }}</span></th>  
                                                                               
                                            </tr>
                                        </thead>
                                        <tbody>                                                            
                                            <tr id="trnorecords" v-if="UserList.length==0">
                                                <td colspan="20" class="text-danger text-center no-record">
                                                    {{ $t('NoRecordfound') }}
                                                </td>
                                            </tr>                                
                                            <tr v-for="(member,index) in UserList" :key="index">                                                  
                                                <td> {{ member.NAME || '--' }} </td>
                                                <td>{{ member.is_Alias_Name || '--'}}</td>
                                                <td v-if="member.USER_ROLE=='LEAD'" class="text-center">
                                                    <span class="badge badge-info font-14 p-2 text-white font-weight-400">{{$t('Lead')}}</span>
                                                </td>
                                                <td v-else class="text-center">
                                                    <span  class="badge badge-warning font-14 p-2 text-white font-weight-400">{{$t('User')}}</span> 
                                                </td>                                                                                                
                                            </tr> 
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        </div>
                        <div class="row flex-row-reverse mt-3">
                            <div class="col-md-12 text-right">                                
                                    <a href="javascript:;" title="" id="ancAddTeamCancel" data-toggle-tooltip="tooltip"
                                        data-original-title="Cancel" @click="CloseAddBacklog" class="btn btn-danger formbtn widthhalf"><i
                                            class="fa fa-close pr-2"></i>{{$t("Cancel")  }}</a>
                            </div>
                        </div>
                    </div>   
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    props:{
        TeamId:{
            type:Number
        },
        TabsArray:{
            type:Array
        }
    },
    data(){
        return{
            UserList:[],
            isLoading:false
        }
    },
    computed: {
  projectTeamName() {
    if (!this.TabsArray || !this.TabsArray.length) {
      return 'Team'
    }
    const tab = this.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")
    return tab?.displayName || 'Team'
  }
    },
    created:function(){
      
        this.GetAssociateUserList();
        
    },
    methods:{
        
        GetAssociateUserList(){
            this.isLoading=true;
            var url=`TeamId=${this.TeamId}`;
            DataService.GetAssociateUserList(url).then((response)=>{
                if(response.data.result.length>0){
                    this.UserList=response.data.result;
                }
                this.isLoading=false;
            })
        },
        CloseAddBacklog(){
            this.$parent.IsUser=false;
        }
    }
}
</script>